#include <iostream>
#include <string>
#include <vector>

struct Logger {
    void log(const std::string& msg) {
        std::cout << msg << "\n";
    }
};

class Processor {
public:
    void processAll(const std::vector<std::string>& items, Logger& logger) {
        for (const auto& item : items)
            logger.log("Processing: " + item);
        logger.log("Done: " + std::to_string(items.size()) + " items");
    }
};

int main() {
    int n{};
    std::cin >> n;
    std::vector<std::string> items(static_cast<std::size_t>(n));
    for (int i = 0; i < n; ++i)
        std::cin >> items[static_cast<std::size_t>(i)];
    Logger lg;
    Processor proc;
    proc.processAll(items, lg);
    return 0;
}

